unsigned char *read_stdin_to_bytes(size_t *out_size)
{
    // Initial buffer size
    size_t buffer_size = 1024;
    size_t total_read = 0;

    // Allocate initial buffer
    unsigned char *buffer = malloc(buffer_size);
    if (buffer == NULL)
    {
        fprintf(stderr, "Memory allocation failed\n");
        return NULL;
    }

    // Read stdin in chunks
    int ch;
    while ((ch = getchar()) != EOF)
    {
        // Resize buffer if needed
        if (total_read >= buffer_size)
        {
            buffer_size *= 2;
            unsigned char *new_buffer = realloc(buffer, buffer_size);
            if (new_buffer == NULL)
            {
                fprintf(stderr, "Memory reallocation failed\n");
                free(buffer);
                return NULL;
            }
            buffer = new_buffer;
        }

        // Store the character
        buffer[total_read++] = (unsigned char)ch;
    }

    // Set the output size
    *out_size = total_read;
    return buffer;
}

int main()
{
    size_t bytes_size;
    unsigned char *bytes = read_stdin_to_bytes(&bytes_size);

    if (bytes == NULL)
    {
        fprintf(stderr, "Failed to read stdin\n");
        return 1;
    }

